mapper.select:
select c.sign_at, c.delivery_cycle ,c.id,c.title,c.create_at addDate,c.founder,c.tag,c.worker,c.bonus,b.brand_name founder_name,b1.brand_name worker_name,c.sow from commission c left join brand b on c.founder=b.id left join brand b1 on c.worker = b1.id where 1 = 1 AND c.oasis_id = #{dto.oasisId}
AND (locate(#{dto.q}, c.title)>0 or locate(#{dto.q}, b1.brand_name)>0 or locate(#{dto.q}, b.brand_name)>0)
AND c.tag= #{dto.tag}
AND c.worker = #{dto.worker}
AND DATE_SUB(CURDATE(), INTERVAL 7 DAY) <= date(c.create_at)
AND DATE_SUB(CURDATE(), INTERVAL 1 DAY) <= date(c.create_at)
Order by c.create_At desc
Order by c.create_At

select c.id, c.title, c.bonus, o.avatar as oasisAvatar, o.handle as oasisHandle, o.title as oasisName, c.tag, c.create_at as createAt, c.sign_at as signAt, c.delivery_cycle as deliveryCycle from commission c inner join oasis o on c.oasis_id = o.id where c.worker = #{brandId}
and (locate(#{dto.q}, c.title) > 0 or locate(#{dto.q}, o.title) > 0)
and c.tag = #{dto.tag}
order by c.modified_at desc
